+using System.Net.Http.Json;
+using System.Text;
+using System.Text.Json;
+using Microsoft.EntityFrameworkCore;
+using Microsoft.Extensions.Caching.Distributed;
+using Microsoft.Extensions.Caching.Memory;
+using Microsoft.Extensions.Logging;
+using Microsoft.Extensions.Options;
+using ReleaseNotes.Application;
+using ReleaseNotes.Domain;
+
+namespace ReleaseNotes.Infrastructure;
+
+public sealed class GitHubOptions
+{
+    public const string SectionName = "GitHub";
+    public string ApiBaseUrl { get; set; } = "https://api.github.com";
+    public string Token { get; set; } = string.Empty;
+}
+
+public sealed class AiOptions
+{
+    public const string SectionName = "Ai";
+    public bool Enabled { get; set; }
+    public string Endpoint { get; set; } = string.Empty;
+    public string ApiKey { get; set; } = string.Empty;
+}
+
+public sealed class GitHubApiClient(
+    HttpClient httpClient,
+    IOptions<GitHubOptions> options,
+    IMemoryCache memoryCache) : IGitSourceClient
+{
+    public async Task<IReadOnlyCollection<SourceArtifact>> GetArtifactsAsync(string repository, string baseTag, string targetTag, CancellationToken cancellationToken)
+    {
+        var cacheKey = $"gh:{repository}:{baseTag}:{targetTag}";
+        if (memoryCache.TryGetValue(cacheKey, out IReadOnlyCollection<SourceArtifact>? cached) && cached is not null)
+        {
+            return cached;
+        }
+
+        httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ReleaseNotesAutomation/1.0");
+        if (!string.IsNullOrWhiteSpace(options.Value.Token))
+        {
+            httpClient.DefaultRequestHeaders.Authorization = new System.Net.Http.Headers.AuthenticationHeaderValue("Bearer", options.Value.Token);
+        }
+
+        var compareEndpoint = $"{options.Value.ApiBaseUrl.TrimEnd('/')}/repos/{repository}/compare/{baseTag}...{targetTag}";
+        var compareResult = await httpClient.GetFromJsonAsync<GitHubCompareResponse>(compareEndpoint, cancellationToken);
+        var artifacts = compareResult?.Commits?.Select(c => new SourceArtifact(
+            c.Sha,
+            c.Commit.Message.Split('\n')[0],
+            c.Commit.Message,
+            c.Author?.Login ?? "unknown",
+            Array.Empty<string>(),
+            Array.Empty<string>(),
+            c.Commit.Author.Date)).ToArray() ?? [];
+
+        memoryCache.Set(cacheKey, artifacts, TimeSpan.FromMinutes(10));
+        return artifacts;
+    }
+
+    private sealed class GitHubCompareResponse
+    {
+        public IReadOnlyCollection<GitHubCommit>? Commits { get; set; }
+    }
+
+    private sealed class GitHubCommit
+    {
+        public string Sha { get; set; } = string.Empty;
+        public GitHubCommitDetail Commit { get; set; } = new();
+        public GitHubAuthor? Author { get; set; }
+    }
+
+    private sealed class GitHubCommitDetail
+    {
+        public string Message { get; set; } = string.Empty;
+        public GitHubCommitAuthor Author { get; set; } = new();
+    }
+
+    private sealed class GitHubCommitAuthor
+    {
+        public DateTimeOffset Date { get; set; }
+    }
+
+    private sealed class GitHubAuthor
+    {
+        public string Login { get; set; } = string.Empty;
+    }
+}
+
+public sealed class RuleEngine : IRuleEngine
+{
+    public ReleaseNoteEntry Classify(SourceArtifact artifact)
+    {
+        var text = $"{artifact.Title} {artifact.Body}".ToLowerInvariant();
+        var category = ChangeCategory.Other;
+        var breaking = false;
+
+        if (text.Contains("breaking") || text.Contains("!:"))
+        {
+            category = ChangeCategory.BreakingChange;
+            breaking = true;
+        }
+        else if (text.Contains("feat"))
+        {
+            category = ChangeCategory.Feature;
+        }
+        else if (text.Contains("fix"))
+        {
+            category = ChangeCategory.Fix;
+        }
+        else if (text.Contains("deps") || text.Contains("dependency"))
+        {
+            category = ChangeCategory.Dependency;
+        }
+        else if (text.Contains("improve") || text.Contains("refactor"))
+        {
+            category = ChangeCategory.Improvement;
+        }
+
+        return new ReleaseNoteEntry(artifact.Id, category, artifact.Title, breaking, 0.7d);
+    }
+}
+
+public sealed class AiSemanticService(HttpClient httpClient, IOptions<AiOptions> options) : IAiSemanticService
+{
+    public async Task<ReleaseNoteEntry> RefineClassificationAsync(ReleaseNoteEntry ruleResult, SourceArtifact artifact, CancellationToken cancellationToken)
+    {
+        if (!options.Value.Enabled || string.IsNullOrWhiteSpace(options.Value.Endpoint))
+        {
+            return ruleResult with { Confidence = 0.8d };
+        }
+
+        var payload = new
+        {
+            text = $"{artifact.Title}\n{artifact.Body}",
+            category = ruleResult.Category.ToString()
+        };
+
+        using var request = new HttpRequestMessage(HttpMethod.Post, options.Value.Endpoint)
+        {
+            Content = new StringContent(JsonSerializer.Serialize(payload), Encoding.UTF8, "application/json")
+        };
+
+        if (!string.IsNullOrWhiteSpace(options.Value.ApiKey))
+        {
+            request.Headers.Authorization = new System.Net.Http.Headers.AuthenticationHeaderValue("Bearer", options.Value.ApiKey);
+        }
+
+        using var response = await httpClient.SendAsync(request, cancellationToken);
+        if (!response.IsSuccessStatusCode)
+        {
+            return ruleResult;
+        }
+
+        var aiResponse = await response.Content.ReadFromJsonAsync<AiResponse>(cancellationToken: cancellationToken);
+        if (aiResponse is null)
+        {
+            return ruleResult;
+        }
+
+        var category = Enum.TryParse<ChangeCategory>(aiResponse.Category, true, out var parsed) ? parsed : ruleResult.Category;
+        return ruleResult with
+        {
+            Category = category,
+            Summary = string.IsNullOrWhiteSpace(aiResponse.Summary) ? ruleResult.Summary : aiResponse.Summary,
+            Confidence = aiResponse.Confidence <= 0 ? ruleResult.Confidence : aiResponse.Confidence
+        };
+    }
+
+    public Task<string> BuildSummaryAsync(IReadOnlyCollection<ReleaseNoteEntry> entries, CancellationToken cancellationToken)
+    {
+        var grouped = entries.GroupBy(x => x.Category).Select(g => $"{g.Key}: {g.Count()}");
+        return Task.FromResult($"Release summary -> {string.Join(", ", grouped)}");
+    }
+
+    private sealed class AiResponse
+    {
+        public string Category { get; set; } = string.Empty;
+        public string Summary { get; set; } = string.Empty;
+        public double Confidence { get; set; }
+    }
+}
+
+public sealed class ReleaseNotesRepository(ReleaseNotesDbContext dbContext) : IReleaseNotesRepository
+{
+    public async Task SaveJobAsync(ReleaseNoteJob job, CancellationToken cancellationToken)
+    {
+        await dbContext.Jobs.AddAsync(job.ToEntity(), cancellationToken);
+        await dbContext.SaveChangesAsync(cancellationToken);
+    }
+
+    public async Task UpdateJobAsync(ReleaseNoteJob job, CancellationToken cancellationToken)
+    {
+        dbContext.Jobs.Update(job.ToEntity());
+        await dbContext.SaveChangesAsync(cancellationToken);
+    }
+
+    public async Task SaveDocumentAsync(ReleaseNoteDocument document, CancellationToken cancellationToken)
+    {
+        await dbContext.Documents.AddAsync(document.ToEntity(), cancellationToken);
+        await dbContext.SaveChangesAsync(cancellationToken);
+    }
+
+    public async Task<ReleaseNoteDocument?> GetDocumentAsync(Guid id, CancellationToken cancellationToken)
+    {
+        var entity = await dbContext.Documents.AsNoTracking().FirstOrDefaultAsync(x => x.Id == id, cancellationToken);
+        return entity?.ToModel();
+    }
+
+    public async Task<IReadOnlyCollection<ReleaseNoteDocument>> GetLatestAsync(int count, CancellationToken cancellationToken)
+    {
+        return await dbContext.Documents.AsNoTracking()
+            .OrderByDescending(x => x.GeneratedAt)
+            .Take(count)
+            .Select(x => x.ToModel())
+            .ToListAsync(cancellationToken);
+    }
+}
+
+public sealed class RedisLockService(IDistributedCache cache) : IDistributedLockService
+{
+    public async Task<IAsyncDisposable?> TryAcquireAsync(string key, TimeSpan ttl, CancellationToken cancellationToken)
+    {
+        var existing = await cache.GetStringAsync(key, cancellationToken);
+        if (!string.IsNullOrWhiteSpace(existing))
+        {
+            return null;
+        }
+
+        await cache.SetStringAsync(key, "1", new DistributedCacheEntryOptions { AbsoluteExpirationRelativeToNow = ttl }, cancellationToken);
+        return new CacheKeyReleaser(cache, key);
+    }
+
+    private sealed class CacheKeyReleaser(IDistributedCache cache, string key) : IAsyncDisposable
+    {
+        public async ValueTask DisposeAsync() => await cache.RemoveAsync(key);
+    }
+}
+
+public sealed class NullProgressNotifier : IProgressNotifier
+{
+    public Task ReportAsync(Guid jobId, string stage, string message, CancellationToken cancellationToken) => Task.CompletedTask;
+}
