+using System.Net.Http.Json;
+using System.Text;
+using System.Text.Json;
+using Microsoft.Extensions.Options;
+using ReleaseNotes.Application.Interfaces;
+using ReleaseNotes.Domain.Enums;
+using ReleaseNotes.Domain.Models;
+using ReleaseNotes.Infrastructure.Options;
+
+namespace ReleaseNotes.Infrastructure.Services;
+
+public sealed class AiSemanticService(HttpClient httpClient, IOptions<AiOptions> options) : IAiSemanticService
+{
+    public async Task<ReleaseNoteEntry> RefineClassificationAsync(ReleaseNoteEntry ruleResult, SourceArtifact artifact, CancellationToken cancellationToken)
+    {
+        if (!options.Value.Enabled || string.IsNullOrWhiteSpace(options.Value.Endpoint))
+        {
+            return ruleResult with { Confidence = 0.8d };
+        }
+
+        var payload = new
+        {
+            text = $"{artifact.Title}\n{artifact.Body}",
+            category = ruleResult.Category.ToString()
+        };
+
+        using var request = new HttpRequestMessage(HttpMethod.Post, options.Value.Endpoint)
+        {
+            Content = new StringContent(JsonSerializer.Serialize(payload), Encoding.UTF8, "application/json")
+        };
+
+        if (!string.IsNullOrWhiteSpace(options.Value.ApiKey))
+        {
+            request.Headers.Authorization = new System.Net.Http.Headers.AuthenticationHeaderValue("Bearer", options.Value.ApiKey);
+        }
+
+        using var response = await httpClient.SendAsync(request, cancellationToken);
+        if (!response.IsSuccessStatusCode)
+        {
+            return ruleResult;
+        }
+
+        var aiResponse = await response.Content.ReadFromJsonAsync<AiResponse>(cancellationToken: cancellationToken);
+        if (aiResponse is null)
+        {
+            return ruleResult;
+        }
+
+        var category = Enum.TryParse<ChangeCategory>(aiResponse.Category, true, out var parsed) ? parsed : ruleResult.Category;
+        return ruleResult with
+        {
+            Category = category,
+            Summary = string.IsNullOrWhiteSpace(aiResponse.Summary) ? ruleResult.Summary : aiResponse.Summary,
+            Confidence = aiResponse.Confidence <= 0 ? ruleResult.Confidence : aiResponse.Confidence
+        };
+    }
+
+    public Task<string> BuildSummaryAsync(IReadOnlyCollection<ReleaseNoteEntry> entries, CancellationToken cancellationToken)
+    {
+        var grouped = entries.GroupBy(x => x.Category).Select(g => $"{g.Key}: {g.Count()}");
+        return Task.FromResult($"Release summary -> {string.Join(", ", grouped)}");
+    }
+
+    private sealed class AiResponse
+    {
+        public string Category { get; set; } = string.Empty;
+        public string Summary { get; set; } = string.Empty;
+        public double Confidence { get; set; }
+    }
+}
